import { useState, useContext } from "react";
import {
  Grid,
  TextField,
  Button,
  Typography,
  makeStyles,
  Paper,
  MenuItem,
} from "@material-ui/core";
import axios from "axios";
import { Redirect } from "react-router-dom";
import ChipInput from "material-ui-chip-input";
import DescriptionIcon from "@material-ui/icons/Description";
import FaceIcon from "@material-ui/icons/Face";
import PhoneInput from "react-phone-input-2";
import "react-phone-input-2/lib/material.css";

import PasswordInput from "../lib/PasswordInput";
import EmailInput from "../lib/EmailInput";
import FileUploadInput from "../lib/FileUploadInput";
import { SetPopupContext } from "../App";
import isAuth from "../lib/isAuth";

const useStyles = makeStyles(() => ({
  body: { padding: "60px 60px" },
  inputBox: { width: "400px" },
  submitButton: { width: "400px" },
}));

const MultifieldInput = ({ education, setEducation }) => {
  const classes = useStyles();

  return (
    <>
      {education.map((obj, key) => (
        <Grid container item spacing={2} className={classes.inputBox} key={key}>
          <Grid item xs={6}>
            <TextField
              label={`Institution Name #${key + 1}`}
              value={obj.institutionName}
              onChange={(e) => {
                const newEdu = [...education];
                newEdu[key].institutionName = e.target.value;
                setEducation(newEdu);
              }}
              variant="outlined"
              fullWidth
            />
          </Grid>
          <Grid item xs={3}>
            <TextField
              label="Start Year"
              type="number"
              value={obj.startYear}
              onChange={(e) => {
                const newEdu = [...education];
                newEdu[key].startYear = e.target.value;
                setEducation(newEdu);
              }}
              variant="outlined"
              fullWidth
            />
          </Grid>
          <Grid item xs={3}>
            <TextField
              label="End Year"
              type="number"
              value={obj.endYear}
              onChange={(e) => {
                const newEdu = [...education];
                newEdu[key].endYear = e.target.value;
                setEducation(newEdu);
              }}
              variant="outlined"
              fullWidth
            />
          </Grid>
        </Grid>
      ))}
      <Grid item>
        <Button
          variant="contained"
          color="secondary"
          onClick={() =>
            setEducation([
              ...education,
              { institutionName: "", startYear: "", endYear: "" },
            ])
          }
          className={classes.inputBox}
        >
          Add another institution
        </Button>
      </Grid>
    </>
  );
};

const Signup = () => {
  const classes = useStyles();
  const setPopup = useContext(SetPopupContext);
  const [loggedin, setLoggedin] = useState(isAuth());

  const [signupDetails, setSignupDetails] = useState({
    type: "applicant",
    email: "",
    password: "",
    name: "",
    education: [],
    skills: [],
    resume: "",
    profile: "",
    bio: "",
    contactNumber: "",
  });

  const [phone, setPhone] = useState("");
  const [education, setEducation] = useState([
    { institutionName: "", startYear: "", endYear: "" },
  ]);

  const [inputErrorHandler, setInputErrorHandler] = useState({
    email: { untouched: true, required: true, error: false, message: "" },
    password: { untouched: true, required: true, error: false, message: "" },
    name: { untouched: true, required: true, error: false, message: "" },
  });

  const handleInput = (key, value) => {
    setSignupDetails((prev) => ({ ...prev, [key]: value }));
  };

  const handleInputError = (key, status, message) => {
    setInputErrorHandler((prev) => ({
      ...prev,
      [key]: {
        required: true,
        untouched: false,
        error: status,
        message,
      },
    }));
  };

  const validateAndSubmit = () => {
    const tmpErrorHandler = { ...inputErrorHandler };
    Object.keys(tmpErrorHandler).forEach((key) => {
      if (tmpErrorHandler[key].required && tmpErrorHandler[key].untouched) {
        tmpErrorHandler[key] = {
          required: true,
          untouched: false,
          error: true,
          message: `${key[0].toUpperCase() + key.slice(1)} is required`,
        };
      }
    });
    setInputErrorHandler(tmpErrorHandler);

    const verified = !Object.values(tmpErrorHandler).some((val) => val.error);
    if (!verified) {
      setPopup({ open: true, severity: "error", message: "Incorrect Input" });
      return;
    }

    const updatedDetails = {
      ...signupDetails,
      education: education
        .filter((edu) => edu.institutionName.trim() !== "")
        .map(({ institutionName, startYear, endYear }) => ({
          institutionName,
          startYear,
          ...(endYear && { endYear }),
        })),
    };

    if (signupDetails.type === "recruiter") {
      updatedDetails.contactNumber = phone ? `+${phone}` : "";
    }

    axios
      .post("http://localhost:4444/api/user/signup", updatedDetails)
      .then((res) => {
        localStorage.setItem("token", res.data.token);
        localStorage.setItem("type", res.data.type);
        setLoggedin(isAuth());
        setPopup({
          open: true,
          severity: "success",
          message: "Signed up successfully",
        });
      })
      .catch((err) => {
        setPopup({
          open: true,
          severity: "error",
          message: err.response?.data?.message || "Signup failed",
        });
        console.error(err.response);
      });
  };

  return loggedin ? (
    <Redirect to="/" />
  ) : (
    <Paper elevation={3} className={classes.body}>
      <Grid container direction="column" spacing={4} alignItems="center">
        <Grid item>
          <Typography variant="h3">Signup</Typography>
        </Grid>

        <Grid item>
          <TextField
            select
            label="Category"
            variant="outlined"
            value={signupDetails.type}
            onChange={(e) => handleInput("type", e.target.value)}
            className={classes.inputBox}
          >
            <MenuItem value="applicant">Applicant</MenuItem>
            <MenuItem value="recruiter">Recruiter</MenuItem>
          </TextField>
        </Grid>

        <Grid item>
          <TextField
            label="Name"
            value={signupDetails.name}
            onChange={(e) => handleInput("name", e.target.value)}
            className={classes.inputBox}
            error={inputErrorHandler.name.error}
            helperText={inputErrorHandler.name.message}
            onBlur={(e) =>
              handleInputError("name", !e.target.value, "Name is required")
            }
            variant="outlined"
          />
        </Grid>

        <Grid item>
          <EmailInput
            label="Email"
            value={signupDetails.email}
            onChange={(e) => handleInput("email", e.target.value)}
            inputErrorHandler={inputErrorHandler}
            handleInputError={handleInputError}
            className={classes.inputBox}
            required={true}
          />
        </Grid>

        <Grid item>
          <PasswordInput
            label="Password"
            value={signupDetails.password}
            onChange={(e) => handleInput("password", e.target.value)}
            className={classes.inputBox}
            error={inputErrorHandler.password.error}
            helperText={inputErrorHandler.password.message}
            onBlur={(e) =>
              handleInputError(
                "password",
                !e.target.value,
                "Password is required"
              )
            }
          />
        </Grid>

        {signupDetails.type === "applicant" ? (
          <>
            <MultifieldInput
              education={education}
              setEducation={setEducation}
            />
            <Grid item>
              <ChipInput
                className={classes.inputBox}
                label="Skills"
                variant="outlined"
                helperText="Press enter to add skills"
                onChange={(chips) => handleInput("skills", chips)}
              />
            </Grid>
            <Grid item>
              <FileUploadInput
                className={classes.inputBox}
                label="Resume (.pdf)"
                icon={<DescriptionIcon />}
                uploadTo="http://localhost:4444/upload/resume"
                handleInput={handleInput}
                identifier="resume"
              />
            </Grid>
            <Grid item>
              <FileUploadInput
                className={classes.inputBox}
                label="Profile Photo (.jpg/.png)"
                icon={<FaceIcon />}
                uploadTo="http://localhost:4444/upload/profile"
                handleInput={handleInput}
                identifier="profile"
              />
            </Grid>
          </>
        ) : (
          <>
            <Grid item style={{ width: "100%" }}>
              <TextField
                label="Bio (upto 250 words)"
                multiline
                rows={8}
                variant="outlined"
                value={signupDetails.bio}
                onChange={(e) => {
                  const words = e.target.value.trim().split(/\s+/);
                  if (words.length <= 250) {
                    handleInput("bio", e.target.value);
                  }
                }}
                style={{ width: "100%" }}
              />
            </Grid>
            <Grid item>
              <PhoneInput
                country={"in"}
                value={phone}
                onChange={(phone) => setPhone(phone)}
              />
            </Grid>
          </>
        )}

        <Grid item>
          <Button
            variant="contained"
            color="primary"
            onClick={validateAndSubmit}
            className={classes.submitButton}
          >
            Signup
          </Button>
        </Grid>
      </Grid>
    </Paper>
  );
};
export default Signup;
